n = /*@__PURE__*/ createMotionProxy(featureBundle, createDomVisualElement);\n\nexport { motion };\n//# sourceMappingURL=proxy.mjs.map\n","import React, { useState, useEffect, useRef } from 'react';\nimport { \n  ArrowLeft, \n  Bike, \n  Phone, \n  Clock, \n  CheckCircle2, \n  MapPin, \n  Send, \n  UserCheck, \n  ShieldCheck,\n  MessageSquare,\n  AlertCircle,\n  ShoppingBag,\n  Package,\n  Check,\n  AlertTriangle,\n  Sparkles\n} from 'lucide-react';\nimport { Order } from '../types';\n\ninterface LiveTrackingProps {\n  order: Order;\n  onBack: () => void;\n  onStatusUpdate?: (status: 'placed' | 'confirmed' | 'dispatched' | 'delivered' | 'refunded') => void;\n  reloadUserProfile?: () => Promise<any>;\n  triggerNotification?: (title: string, message: string, type: 'info' | 'success' | 'warning' | 'promo') => void;\n}\n\nexport default function LiveTracking({ \n  order, \n  onBack, \n  onStatusUpdate,\n  reloadUserProfile,\n  triggerNotification\n}: LiveTrackingProps) {\n  // Cancellation / refund states\n  const [showCancelConfirm, setShowCancelConfirm] = useState(false);\n  const [cancelReason, setCancelReason] = useState('Ordered wrong items or size');\n  const [isCancelling, setIsCancelling] = useState(false);\n  const [showQrLive, setShowQrLive] = useState(true);\n\n  // Chat tracking states and quick responses\n  const [riderMessage, setRiderMessage] = useState<string>('');\n  const [chatHistory, setChatHistory] = useState<Array<{ sender: 'user' | 'rider'; text: string; time: string }>>(() => [\n    { \n      sender: 'rider', \n      text: order.riderName \n        ? `Hi! I am ${order.riderName.split(' ')[0]}, your delivery partner. I am heading to the merchant to collect your order.` \n        : 'Hi! I am your assigned delivery partner. I am heading to the merchant to collect your order.', \n      time: 'Just now' \n    }\n  ]);\n  const chatEndRef = useRef<HTMLDivElement>(null);\n\n  // Auto-scroll chat history\n  useEffect(() => {\n    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });\n  }, [chatHistory]);\n\n  const appendMessage = (sender: 'user' | 'rider', text: string) => {\n    const timeStr = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });\n    setChatHistory(prev => [...prev, { sender, text, time: timeStr }]);\n  };\n\n  const handleSendMessage = (e: React.FormEvent) => {\n    e.preventDefault();\n    if (!riderMessage.trim()) return;\n\n    appendMessage('user', riderMessage);\n    const textSent = riderMessage.toLowerCase();\n    setRiderMessage('');\n\n    // Pre-scheduled smart replies from simulated rider\n    setTimeout(() => {\n      if (textSent.includes('where') || textSent.includes('reach') || textSent.includes('far')) {\n        appendMessage('rider', `I am on my way, passing through main cross-road. I should arrive in about 4-5 mins!`);\n      } else if (textSent.includes('gate') || textSent.includes('security') || textSent.includes('guard')) {\n        appendMessage('rider', 'Understood! I will leave it with the security guard / front desk and place an update.');\n      } else if (textSent.includes('fresh') || textSent.includes('cold') || textSent.includes('ice') || textSent.includes('melt')) {\n        appendMessage('rider', 'Yes! Your chilled products are safely packed inside our cold-preservation thermal wrap.');\n      } else {\n        appendMessage('rider', 'Thank you! Driving safely to your address now.');\n      }\n    }, 1100);\n  };\n\n  // Instant wallet-credit cancellation system\n  const handleTriggerRefund = async () => {\n    setIsCancelling(true);\n    try {\n      const res = await fetch(`/api/orders/${order.id}/refund`, {\n        method: 'POST',\n        headers: {\n          'Content-Type': 'application/json'\n        },\n        body: JSON.stringify({\n          refundReason: cancelReason\n        })\n      });\n\n      const data = await res.json();\n      if (!res.ok) {\n        throw new Error(data.error || 'Failed to cancel and refund your order.');\n      }\n\n      if (triggerNotification) {\n        triggerNotification(\n          \"Refund Processed! 💳\",\n          `₹${order.total} has been credited back to your Daily Mart Wallet instantly.`,\n          \"success\"\n        );\n      }\n\n      if (reloadUserProfile) {\n        await reloadUserProfile();\n      }\n\n      if (onStatusUpdate) {\n        onStatusUpdate('refunded');\n      }\n\n      onBack();\n    } catch (err: any) {\n      alert(err.message || 'Error occurred during cancellation.');\n    } finally {\n      setIsCancelling(false);\n      setShowCancelConfirm(false);\n    }\n  };\n\n  // Dynamic ETA & visual tracker parameters calculations\n  const getDeliveryETAString = (): { minutes: string; subtext: string; themeColor: string } => {\n    if (order.status === 'delivered') {\n      return { minutes: 'Delivered', subtext: 'Successfully completed on time', themeColor: 'text-[#00B853] bg-emerald-50 border-emerald-100' };\n    }\n    if (order.status === 'refunded') {\n      return { minutes: 'Cancelled', subtext: 'Wallet refund has completed', themeColor: 'text-rose-600 bg-rose-50 border-rose-100' };\n    }\n    if (order.status === 'rejected') {\n      return { minutes: 'Rejected', subtext: 'Rejected by merchant', themeColor: 'text-slate-500 bg-slate-50 border-slate-100' };\n    }\n\n    const isDispatched = order.status === 'dispatched';\n    const pStatus = order.packingStatus || 'pending';\n    const dStage = order.deliveryStage || 'pickup_nav';\n\n    if (isDispatched) {\n      if (dStage === 'otp_verify') {\n        return { minutes: 'Arrived! 🚴', subtext: 'Waiting at door to verify PIN', themeColor: 'text-[#00A86B] bg-emerald-50 border-emerald-100 animate-pulse' };\n      }\n      if (dStage === 'delivery_nav') {\n        return { minutes: '3-5 Mins', subtext: 'Rider is speeding down your block', themeColor: 'text-indigo-600 bg-indigo-50 border-indigo-100 font-black' };\n      }\n      return { minutes: '7-10 Mins', subtext: 'Rider is picking up from seller', themeColor: 'text-amber-600 bg-amber-50 border-amber-100' };\n    }\n\n    if (pStatus === 'ready') {\n      return { minutes: '10-12 Mins', subtext: 'Awaiting rider agent assignment', themeColor: 'text-amber-600 bg-amber-50 border-amber-100' };\n    }\n    if (['preparing', 'packing'].includes(pStatus)) {\n      return { minutes: '12-15 Mins', subtext: 'Store agents are sealing ingredients', themeColor: 'text-slate-800 bg-slate-50 border-slate-100 font-extrabold' };\n    }\n\n    return { minutes: '15-20 Mins', subtext: 'Waiting for store acceptance receipt', themeColor: 'text-slate-700 bg-slate-50 border-slate-100' };\n  };\n\n  const etaInfo = getDeliveryETAString();\n\n  // Define the 8 exact statuses requested by the user\n  const timelineSteps = [\n    { \n      label: 'Order Placed', \n      desc: 'We have received your cart list. Budget security verification locked.', \n      icon: CheckCircle2 \n    },\n    { \n      label: 'Seller Accepted', \n      desc: 'Merchant has reviewed store stock and acknowledged packaging receipt.', \n      icon: ShieldCheck \n    },\n    { \n      label: 'Preparing Order', \n      desc: 'Store representatives are hand-picking, scanning & sterile-bagging groceries.', \n      icon: Clock \n    },\n    { \n      label: 'Rider Assigned', \n      desc: 'Nearby delivery partner has accepted coordinates and registered EV unit.', \n      icon: Bike \n    },\n    { \n      label: 'Rider Going to Seller', \n      desc: 'Rider has ignited transit and is traveling to merchant hub.', \n      icon: ShoppingBag \n    },\n    { \n      label: 'Order Picked Up', \n      desc: 'Sealed crate successfully loaded into cold-preservation thermal bag.', \n      icon: Package \n    },\n    { \n      label: 'Out for Delivery', \n      desc: 'Rider is navigation-routing directly to your main entrance pins.', \n      icon: Bike \n    },\n    { \n      label: 'Delivered', \n      desc: 'Crate handed over safely of zero-contact protocols.', \n      icon: UserCheck \n    }\n  ];\n\n  // Helper code to map dynamic system status triggers into the 8 requested steps\n  const getStepStatus = (index: number): 'completed' | 'active' | 'upcoming' => {\n    const status = order.status;\n    const pStatus = order.packingStatus || 'pending';\n    const dStage = order.deliveryStage || 'pickup_nav';\n    const hasRider = !!order.riderId;\n\n    if (status === 'delivered') return 'completed';\n\n    switch (index) {\n      case 0: // 1. Order Placed\n        return 'completed'; // Always passed once on this tracking view\n\n      case 1: // 2. Seller Accepted\n        if (['confirmed', 'dispatched'].includes(status)) return 'completed';\n        if (pStatus === 'accepted') return 'active';\n        return status === 'placed' ? 'active' : 'upcoming'; // Placed is current active until confirmed\n\n      case 2: // 3. Preparing Order\n        if (status === 'dispatched' || pStatus === 'ready') return 'completed';\n        if (['preparing', 'packing'].includes(pStatus)) return 'active';\n        if (status === 'confirmed') return 'active'; // Confirmed maps to seller accepting & prepacking\n        return 'upcoming';\n\n      case 3: // 4. Rider Assigned\n        if (hasRider) return 'completed';\n        if (pStatus === 'ready' && !hasRider) return 'active';\n        return 'upcoming';\n\n      case 4: // 5. Rider Going to Seller\n        if (hasRider && dStage === 'pickup_nav') return 'active';\n        if (hasRider && (dStage === 'delivery_nav' || dStage === 'otp_verify')) return 'completed';\n        return 'upcoming';\n\n      case 5: // 6. Order Picked Up\n        if (hasRider && (dStage === 'delivery_nav' || dStage === 'otp_verify')) return 'completed';\n        if (hasRider && pStatus === 'ready' && dStage === 'pickup_nav') {\n          // If rider is assigned, checking item collected\n          return 'upcoming';\n        }\n        return 'upcoming';\n\n      case 6: // 7. Out for Delivery\n        if (hasRider && (dStage === 'delivery_nav' || dStage === 'otp_verify')) return 'active';\n        return 'upcoming';\n\n      case 7: // 8. Delivered\n        return order.status === 'delivered' ? 'completed' : 'upcoming';\n\n      default:\n        return 'upcoming';\n    }\n  };\n\n  // Generate a premium completed stage timestamp based on order.createdAt (+ offsets)\n  const getSimulatedStepTime = (orderCreatedAt: string, stepIndex: number) => {\n    try {\n      const createdDate = new Date(orderCreatedAt);\n      // Realistic minutes elapsed relative to creation\n      const offsetsInMinutes = [0, 1.2, 3.4, 4.0, 4.8, 6.0, 7.5, 11.0];\n      const stepTime = new Date(createdDate.getTime() + offsetsInMinutes[stepIndex] * 60 * 1000);\n      const now = new Date();\n      // Floor to now so we never show future times\n      const displayTime = stepTime < now ? stepTime : now;\n      return displayTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });\n    } catch (e) {\n      return '';\n    }\n  };\n\n  // Determine an overall visual slider progress value (0 to 100) for the top CSS tracker\n  const getOverallProgressPercentage = (): number => {\n    let completedStepsCount = 0;\n    for (let i = 0; i < 8; i++) {\n      if (getStepStatus(i) === 'completed') {\n        completedStepsCount++;\n      }\n    }\n    return Math.floor((completedStepsCount / 8) * 100);\n  };\n\n  const progressPercentage = getOverallProgressPercentage();\n\n  // Chat tracking alerts\n  const sentStepsRef = useRef<Record<number, boolean>>({});\n  useEffect(() => {\n    // Sync simulated conversational notifications with steps\n    let currentStepIndex = 0;\n    for (let i = 0; i < 8; i++) {\n      if (getStepStatus(i) === 'active') {\n        currentStepIndex = i;\n        break;\n      }\n    }\n    if (currentStepIndex === 0) return;\n    if (sentStepsRef.current[currentStepIndex]) return;\n    sentStepsRef.current[currentStepIndex] = true;\n\n    if (currentStepIndex === 1) {\n      appendMessage('rider', 'Order confirmed by seller! Packed & sealed cleanly. Moving shortly.');\n    } else if (currentStepIndex === 3) {\n      appendMessage('rider', 'Secure dispatch verified! I have loaded your groceries into my thermally insulated box.');\n    } else if (currentStepIndex === 5) {\n      appendMessage('rider', \"I've picked up your order from Oliver's. Racing over right now! 🚴\");\n    } else if (currentStepIndex === 6) {\n      appendMessage('rider', \"I'm on my way! Safe travel transit is active. ETA is 3-5 minutes, please keep OTP handy.\");\n    }\n  }, [order.id, order.status, order.packingStatus, order.deliveryStage]);\n\n  return (\n    <div id=\"live-tracking-panel\" className=\"max-w-4xl mx-auto space-y-4 animate-fade-in pl-1 pr-1 pb-16\">\n      \n      {/* Navigation Header */}\n      <div className=\"flex items-center justify-between bg-white rounded-2xl p-3 border border-slate-100 shadow-xs\">\n        <button\n          onClick={onBack}\n          className=\"flex items-center gap-1 text-slate-500 hover:text-indigo-600 font-extrabold text-xs cursor-pointer transition\"\n        >\n          <ArrowLeft className=\"w-4 h-4\" /> Back to Orders\n        </button>\n        <span className=\"text-[10px] font-black tracking-wider text-indigo-600 bg-indigo-50 border border-indigo-100 uppercase px-2 py-1 rounded-md flex items-center gap-1 animate-pulse\">\n          <Sparkles className=\"w-3 h-3 text-indigo-500\" />\n          DAILY MART DISPATCH FEEDBACK ACTIVE\n        </span>\n      </div>\n\n      {/* TOP DASHBOARD CARD: REAL-TIME TIMELINE FEEDBACK ETA BANNERS */}\n      <div className=\"bg-white rounded-3xl p-5 border border-slate-150 shadow-xs text-left relative overflow-hidden\">\n        {/* Background visual styling loops */}\n        <div className=\"absolute right-0 top-0 bottom-0 w-1/3 opacity-5 pointer-events-none bg-[radial-gradient(#6366f1_1px,transparent_1px)] bg-[size:12px_12px] hidden sm:block\"></div>\n\n        <div className=\"flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 border-b border-slate-100 pb-4\">\n          <div className=\"space-y-1\">\n            <p className=\"text-[10px] text-slate-400 font-bold uppercase tracking-wider\">Estimated Dropoff Countdown</p>\n            <h2 className=\"text-3xl font-black text-slate-950 font-sans tracking-tight\">\n              {etaInfo.minutes}\n            </h2>\n            <p className=\"text-xs text-slate-500 font-medium\">\n              {etaInfo.subtext}\n            </p>\n          </div>\n\n          {/* SECURE DELIVERY PIN BLOCK */}\n          <div className=\"p-3 bg-emerald-50 hover:bg-emerald-100/75 border border-emerald-150 rounded-2xl flex items-center gap-4 transition duration-200 w-full sm:w-auto\">\n            <div className=\"bg-[#00B853] text-white p-2 rounded-xl\">\n              <CheckCircle2 className=\"w-5 h-5\" />\n            </div>\n            <div>\n              <p className=\"text-[9px] text-[#008A3E] font-black uppercase tracking-wider block\">Share OTP with Rider</p>\n              <p className=\"text-xl font-black text-emerald-950 font-mono tracking-widest mt-0.5\">{order.otp || '1111'}</p>\n            </div>\n          </div>\n        </div>\n\n        {/* MODERN CUSTOM TRANSIT PROGRESS SLIDER (No maps representation) */}\n        <div className=\"pt-5 space-y-2\">\n          <div className=\"flex justify-between text-[10px] text-slate-500 font-bold uppercase tracking-wider\">\n            <span>Sealing Bag</span>\n            <span>Rider Dispatched</span>\n            <span>At Your Gate</span>\n          </div>\n\n          <div className=\"relative w-full h-3.5 bg-slate-100 rounded-full overflow-hidden border border-slate-200\">\n            <div \n              className=\"absolute left-0 top-0 bottom-0 bg-gradient-to-r from-indigo-500 via-purple-500 to-indigo-600 rounded-full transition-all duration-1000 ease-out\"\n              style={{ width: `${Math.max(5, progressPercentage)}%` }}\n            >\n              <div className=\"absolute right-1 top-[2px] w-2 h-2 bg-white rounded-full animate-ping\"></div>\n            </div>\n          </div>\n\n          <div className=\"flex justify-between items-center\">\n            <span className=\"text-[10px] font-bold text-slate-400 font-mono\">\n              ORDER REF: #{order.id} • {order.paymentMethod}\n            </span>\n            <span className=\"text-[10px] font-black text-indigo-600 bg-indigo-50 px-2.5 py-0.5 rounded-lg\">\n              SYSTEM SYNC COMPLETED ({progressPercentage}%)\n            </span>\n          </div>\n        </div>\n      </div>\n\n      {/* CORE 2-COLUMN LAYOUT PANEL */}\n      <div className=\"grid grid-cols-1 md:grid-cols-12 gap-4\">\n        \n        {/* LEFT COLUMN: SWIGGY/BLINKIT STYLE 8-STAGE VERTICAL TIMELINE CARDS */}\n        <div className=\"bg-white rounded-3xl p-5 border border-slate-100 shadow-xs md:col-span-6 text-left space-y-4\">\n          <div className=\"border-b border-slate-100 pb-3\">\n            <h3 className=\"font-extrabold text-sm text-slate-850 uppercase tracking-wider flex items-center gap-1.5 font-sans\">\n              <span className=\"w-2.5 h-2.5 bg-indigo-600 rounded-full\"></span>\n              Live Logistics Status Tracker\n            </h3>\n            <p className=\"text-[10.5px] text-slate-400 mt-0.5 font-medium leading-normal\">\n              Direct updates received in real-time. Maps are retired to provide secure, distraction-free order checkpoints.\n            </p>\n          </div>\n\n          {/* Timeline Nodes */}\n          <div className=\"relative pl-3 pt-2 space-y-5\">\n            {/* Connecting Vertical Track Thread Bar */}\n            <div className=\"absolute left-[14px] top-4 bottom-4 w-0.5 bg-slate-100\"></div>\n\n            {timelineSteps.map((s, idx) => {\n              const statusState = getStepStatus(idx);\n              const isDone = statusState === 'completed';\n              const isActive = statusState === 'active';\n              const StepIcon = s.icon;\n              \n              return (\n                <div key={idx} className=\"flex gap-4 relative z-10 transition-all duration-300\">\n                  {/* Indicator Bulb Node Dot */}\n                  <div className=\"relative shrink-0\">\n                    <div className={`w-7.5 h-7.5 rounded-full flex items-center justify-center border text-xs transition-all duration-300 ${\n                      isDone \n                        ? 'bg-[#00B853] border-[#00B853] text-white shadow-sm' \n                        : isActive\n                          ? 'bg-amber-100 border-amber-500 text-amber-700 ring-4 ring-amber-400/20 scale-105 font-bold animate-pulse'\n                          : 'bg-white border-slate-200 text-slate-400'\n                    }`}>\n                      {isDone ? (\n                        <Check className=\"w-3.5 h-3.5 stroke-[3]\" />\n                      ) : (\n                        <StepIcon className=\"w-3.5 h-3.5\" />\n                      )}\n                    </div>\n                  </div>\n\n                  {/* Main descriptions panel */}\n                  <div className=\"flex-1 min-w-0\">\n                    <div className=\"flex items-start justify-between gap-2\">\n                      <h4 className={`text-xs font-black tracking-tight leading-normal ${\n                        isDone ? 'text-slate-800' : isActive ? 'text-amber-700' : 'text-slate-450'\n                      }`}>\n                        {s.label}\n                      </h4>\n                      {isDone && (\n                        <span className=\"text-[9px] text-[#008A3E] font-black font-mono tracking-wider bg-emerald-50 px-1.5 py-0.5 rounded uppercase\">\n                          {getSimulatedStepTime(order.createdAt, idx)}\n                        </span>\n                      )}\n                      {isActive && (\n                        <span className=\"text-[9px] text-amber-600 font-extrabold font-mono uppercase bg-amber-50 px-1.5 py-0.5 rounded animate-pulse\">\n                          Active Now\n                        </span>\n                      )}\n                    </div>\n                    <p className={`text-[10px] mt-0.5 leading-relaxed leading-normal ${\n                      isDone ? 'text-slate-500 font-medium' : isActive ? 'text-slate-600 font-semibold' : 'text-slate-400'\n                    }`}>\n                      {s.desc}\n                    </p>\n                  </div>\n                </div>\n              );\n            })}\n          </div>\n\n          {/* Cancellation Option Link */}\n          {order.status !== 'delivered' && order.status !== 'refunded' && order.status !== 'rejected' && (\n            <div className=\"pt-4 border-t border-slate-100\">\n              {!showCancelConfirm ? (\n                <button\n                  type=\"button\"\n                  onClick={() => setShowCancelConfirm(true)}\n                  className=\"w-full py-2 bg-rose-50 hover:bg-rose-100 text-rose-600 font-extrabold text-[11px] rounded-xl flex items-center justify-center gap-1.5 transition active:scale-95 cursor-pointer border border-rose-100/65 uppercase tracking-wide\"\n                >\n                  🗑️ Cancel Purchase & Refund to Wallet\n                </button>\n              ) : (\n                <div className=\"bg-rose-50/50 border border-rose-100 p-3.5 rounded-2xl space-y-3\">\n                  <div className=\"flex items-start gap-2\">\n                    <AlertCircle className=\"w-4 h-4 text-rose-500 shrink-0 mt-0.5\" />\n                    <div>\n                      <h4 className=\"font-black text-[11px] text-rose-900 uppercase\">Confirm Cancel Purchase?</h4>\n                      <p className=\"text-[10px] text-rose-700 font-semibold mt-0.5 leading-relaxed\">\n                        This order will be terminated. Since payment was completed, a full refund of <span className=\"font-black text-rose-950 font-mono\">₹{order.total}</span> will be credited instantly back to your Daily Mart Wallet balance.\n                      </p>\n                    </div>\n                  </div>\n\n                  <div className=\"space-y-1.5\">\n                    <label className=\"text-[9px] font-black text-rose-800 uppercase block tracking-wide\">Cancellation Reason</label>\n                    <select\n                      value={cancelReason}\n                      onChange={(e) => setCancelReason(e.target.value)}\n                      className=\"w-full bg-white border border-rose-200 text-slate-800 py-1.5 px-2 text-xs rounded-xl focus:outline-none focus:ring-1 focus:ring-rose-500 font-black cursor-pointer\"\n                    >\n                      <option value=\"Ordered wrong items or size\">Ordered wrong items/variant</option>\n                      <option value=\"Change of mind\">Ordered by mistake</option>\n                      <option value=\"Rider taking longer than 10 mins\">Rider taking too long</option>\n                      <option value=\"Host destination address needs correction\">Incorrect drop address</option>\n                      <option value=\"Other / Support case\">Other support issue</option>\n                    </select>\n                  </div>\n\n                  <div className=\"grid grid-cols-2 gap-2 text-[10px] font-black uppercase\">\n                    <button\n                      type=\"button\"\n                      onClick={() => setShowCancelConfirm(false)}\n                      className=\"py-2 bg-slate-150 hover:bg-slate-200 text-slate-600 rounded-xl transition cursor-pointer\"\n                      disabled={isCancelling}\n                    >\n                      Nevermind, Keep\n                    </button>\n                    <button\n                      type=\"button\"\n                      onClick={handleTriggerRefund}\n                      className=\"py-2 bg-rose-600 hover:bg-rose-700 text-white rounded-xl transition cursor-pointer\"\n                      disabled={isCancelling}\n                    >\n                      {isCancelling ? 'Processing...' : 'Cancel & Refund'}\n                    </button>\n                  </div>\n                </div>\n              )}\n            </div>\n          )}\n\n        </div>\n\n        {/* RIGHT COLUMN: RIDER DETAILS + LIVE-CHAT SIMULATION + MOBILE SYNC PANEL */}\n        <div className=\"md:col-span-6 space-y-4\">\n          \n          {/* Rider Assigned Profile Block */}\n          {order.riderId ? (\n            <div className=\"bg-white rounded-3xl p-4 border border-slate-100 shadow-xs flex flex-col sm:flex-row items-start sm:items-center justify-between gap-3 text-left\">\n              <div className=\"flex items-center gap-3\">\n                <div className=\"w-12 h-12 bg-indigo-50/70 text-indigo-700 rounded-full border border-indigo-100 flex items-center justify-center font-black text-sm uppercase\">\n                  {order.riderName ? order.riderName.split(' ').map((n: string) => n[0]).join('').substring(0, 2) : 'RD'}\n                </div>\n                <div>\n                  <div className=\"flex items-center gap-1.5\">\n                    <h5 className=\"font-black text-sm text-slate-800\">{order.riderName || 'Premium Delivery Executive'}</h5>\n                    <span className=\"text-[8px] bg-indigo-50 text-indigo-700 px-1.5 py-0.5 rounded font-black uppercase tracking-wide border border-indigo-100 shrink-0\">\n                      Active EV Agent\n                    </span>\n                  </div>\n                  <p className=\"text-[10px] text-slate-400 font-mono mt-0.5 leading-none\">Daily Mart Electric Fleet • Zero Emission Transit</p>\n                  {order.riderPhone && (\n                    <p className=\"text-[10px] text-slate-500 font-sans mt-1\">Phone: <span className=\"font-extrabold text-slate-700\">{order.riderPhone}</span></p>\n                  )}\n                </div>\n              </div>\n              \n              {order.riderPhone && (\n                <a \n                  href={`tel:${order.riderPhone}`}\n                  className=\"w-10 h-10 rounded-full bg-emerald-50 text-emerald-600 hover:bg-emerald-100 flex items-center justify-center transition shrink-0 self-end sm:self-center border border-emerald-100 active:scale-95 cursor-pointer\"\n                >\n                  <Phone className=\"w-4.5 h-4.5\" />\n                </a>\n              )}\n            </div>\n          ) : (\n            <div className=\"bg-amber-50/50 rounded-3xl p-4 border border-amber-100 shadow-xs flex items-center gap-3 text-left\">\n              <div className=\"w-12 h-12 bg-amber-100 text-amber-800 rounded-full flex items-center justify-center text-lg shadow-inner\">\n                ⏳\n              </div>\n              <div>\n                <h5 className=\"font-black text-sm text-amber-900\">Rider assignation queue active</h5>\n                <p className=\"text-[10.5px] text-amber-700 font-medium leading-relaxed leading-normal mt-0.5\">\n                  Your order packing status is complete. Connecting with proximate EV carriers for delivery routing.\n                </p>\n              </div>\n            </div>\n          )}\n\n          {/* SMS / CHAT SIMULATION PANEL */}\n          <div className=\"bg-white rounded-3xl border border-slate-100 overflow-hidden shadow-xs flex flex-col h-64 text-left\">\n            <div className=\"p-3 bg-slate-50 border-b border-slate-100 flex items-center gap-2\">\n              <MessageSquare className=\"w-4 h-4 text-indigo-600\" />\n              <span className=\"text-xs font-black text-slate-800 font-sans uppercase tracking-tight\">Direct Message Link</span>\n            </div>\n\n            {/* Chat conversation lines */}\n            <div className=\"flex-1 overflow-y-auto p-3 space-y-2\">\n              {chatHistory.map((chat, cidx) => {\n                const isRider = chat.sender === 'rider';\n                return (\n                  <div \n                    key={cidx} \n                    className={`flex ${isRider ? 'justify-start' : 'justify-end'}`}\n                  >\n                    <div className={`max-w-[80%] rounded-2xl px-3 py-1.5 text-xs ${\n                      isRider \n                        ? 'bg-slate-100 text-slate-800 rounded-bl-none border border-slate-150' \n                        : 'bg-indigo-600 text-white rounded-br-none font-medium shadow-xs'\n                    }`}>\n                      <p className=\"leading-relaxed\">{chat.text}</p>\n                      <span className={`text-[8px] block text-right mt-0.5 ${\n                        isRider ? 'text-slate-400 font-mono' : 'text-indigo-200 font-mono'\n                      }`}>\n                        {chat.time}\n                      </span>\n                    </div>\n                  </div>\n                );\n              })}\n              <div ref={chatEndRef}></div>\n            </div>\n\n            {/* Quick Presets row tags */}\n            <div className=\"px-2 py-1.5 bg-slate-50 border-t border-slate-100 flex flex-wrap gap-1.5\">\n              {[\n                { text: \"Leave with guard 👮\", response: \"Understood! I will drop it off at the lobby security guard block and notify.\" },\n                { text: \"Call upon arrival 📞\", response: \"Yes, sure. I will dial your phone upon arriving at the main gate.\" },\n                { text: \"Keep ice cream sealed 🍦\", response: \"Absolutely. Chilled cargo is stored within padded high-retention packs.\" },\n                { text: \"Don't ring the bell 🤫\", response: \"Understood. I will place it softly on the door sill and text you.\" }\n              ].map((preset, pIdx) => (\n                <button\n                  key={pIdx}\n                  type=\"button\"\n                  onClick={() => {\n                    appendMessage('user', preset.text);\n                    setTimeout(() => {\n                      appendMessage('rider', preset.response);\n                    }, 1000);\n                  }}\n                  className=\"bg-white hover:bg-indigo-50 text-slate-650 hover:text-indigo-750 border border-slate-200 hover:border-indigo-200 px-2 py-0.5 rounded-full text-[9px] font-black transition cursor-pointer active:scale-95 uppercase tracking-wide\"\n                >\n                  {preset.text}\n                </button>\n              ))}\n            </div>\n\n            {/* Input typing field */}\n            <form onSubmit={handleSendMessage} className=\"p-2 border-t border-slate-100 flex gap-2\">\n              <input\n                type=\"text\"\n                placeholder={`Text ${order.riderName ? order.riderName.split(' ')[0] : 'your rider'}...`}\n                value={riderMessage}\n                onChange={(e) => setRiderMessage(e.target.value)}\n                className=\"flex-1 bg-slate-50 border border-slate-250 hover:border-slate-350 px-3 py-1.5 text-xs rounded-xl focus:outline-none focus:ring-1 focus:ring-indigo-500\"\n              />\n              <button \n                type=\"submit\"\n                className=\"p-1.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition active:scale-90\"\n              >\n                <Send className=\"w-4 h-4\" />\n              </button>\n            </form>\n          </div>\n\n          {/* SHARE STATE/QR WIDGET SECTION */}\n          <div className=\"bg-slate-50 rounded-3xl p-3 border border-slate-100 space-y-2 text-left\">\n            <div className=\"flex items-center justify-between cursor-pointer group select-none\" onClick={() => setShowQrLive(!showQrLive)}>\n              <div className=\"flex items-center gap-2\">\n                <span className=\"text-xs\">📱</span>\n                <span className=\"text-[10px] font-black text-slate-700 uppercase tracking-wider font-sans\">Track LIVE on smartphone screen</span>\n              </div>\n              <span className=\"text-[9.5px] font-black text-indigo-600 bg-indigo-100/50 px-2.5 py-0.5 rounded-lg group-hover:bg-indigo-150 transition-colors whitespace-nowrap\">\n                {showQrLive ? 'Hide QR Code' : 'Show Scan QR'}\n              </span>\n            </div>\n            \n            {showQrLive && (\n              <div className=\"pt-2 border-t border-slate-150/50 flex gap-3 animate-fade-in items-center\">\n                <div className=\"p-1 px-1.5 bg-white border border-slate-200 rounded-xl shrink-0 shadow-xs\">\n                  <img\n                    src={`https://api.qrserver.com/v1/create-qr-code/?size=95x95&data=${encodeURIComponent(\n                      typeof window !== 'undefined' && !window.location.host.includes('localhost') \n                        ? window.location.origin \n                        : \"https://ais-pre-u4qsdpfkg63jdkgnj3beph-260720568939.asia-southeast1.run.app\"\n                    )}`}\n                    alt=\"Scan Live Link\"\n                    className=\"w-16 h-16 object-contain\"\n                  />\n                </div>\n                <div>\n                  <p className=\"text-[10.5px] text-slate-800 font-extrabold leading-normal\">Open tracker bypass sandbox</p>\n                  <p className=\"text-[9.5px] text-slate-450 mt-0.5 leading-relaxed leading-normal\">\n                    Avoid iframe viewport constraints of AI Studio workspace. Scan with your camera app to tracking order and synchronize delivery state natively.\n                  </p>\n                </div>\n              </div>\n            )}\n          </div>\n\n        </div>\n\n      </div>\n\n    </div>\n  );\n}\n","import React, { useState } from 'react';\nimport { MapPin, Plus, Trash2, Home, Briefcase, PlusCircle, ArrowLeft } from 'lucide-react';\n\ninterface AddressItem {\n  id: string;\n  label: string;\n  address: string;\n}\n\ninterface AddressesManagerProps {\n  savedAddresses: AddressItem[];\n  activeAddressId: string | null;\n  onSelect: (address: string, id: string) => void;\n  onAdd: (label: string, address: string) => void;\n  onDelete: (id: string) => void;\n  onBack: () => void;\n}\n\nexport default function AddressesManager({\n  savedAddresses,\n  activeAddressId,\n  onSelect,\n  onAdd,\n  onDelete,\n  onBack\n}: AddressesManagerProps) {\n  const [newLabel, setNewLabel] = useState('Home');\n  const [newAddress, setNewAddress] = useState('');\n  const [customLabel, setCustomLabel] = useState('');\n  const [showForm, setShowForm] = useState(false);\n\n  // Address templates\n  const presets = ['Home', 'Work', 'Friends', 'Gym', 'Parents'];\n\n  const handleSubmit = (e: React.FormEvent) => {\n    e.preventDefault();\n    const finalLabel = newLabel === 'Custom' ? customLabel.trim() : newLabel;\n    if (!finalLabel || !newAddress.trim()) return;\n\n    onAdd(finalLabel, newAddress.trim());\n    setNewAddress('');\n    setCustomLabel('');\n    setShowForm(false);\n  };\n\n  const getLabelIcon = (label: string) => {\n    const l = label.toLowerCase();\n    if (l.includes('home')) return <Home className=\"w-4 h-4 text-emerald-600\" />;\n    if (l.includes('work') || l.includes('office')) return <Briefcase className=\"w-4 h-4 text-emerald-600\" />;\n    return <MapPin className=\"w-4 h-4 text-emerald-600\" />;\n  };\n\n  return (\n    <div id=\"addresses-manager\" className=\"max-w-md mx-auto bg-white rounded-3xl p-5 border border-slate-100 shadow-sm text-left space-y-5\">\n      {/* Head */}\n      <div className=\"flex items-center justify-between border-b border-slate-100 pb-3\">\n        <button\n          onClick={onBack}\n          className=\"flex items-center gap-1 text-slate-500 hover:text-emerald-700 font-bold text-xs\"\n        >\n          <ArrowLeft className=\"w-4 h-4\" /> Back to Profile\n        </button>\n        <span className=\"text-[10px] font-black tracking-widest text-emerald-600 uppercase\">\n          Saved Destinations\n        </span>\n      </div>\n\n      {/* List */}\n      <div className=\"space-y-2.5\">\n        <label className=\"text-[10px] font-black text-slate-400 uppercase tracking-widest block\">Choose Delivery Address:</label>\n        {savedAddresses.map((ad) => {\n          const isActive = activeAddressId === ad.id;\n          return (\n            <div\n              key={ad.id}\n              className={`p-3 rounded-2xl border transition duration-150 flex items-start gap-3 relative group ${\n                isActive \n                  ? 'border-emerald-600 bg-emerald-50/50 ring-1 ring-emerald-500/15'\n                  : 'border-slate-150 bg-white hover:bg-slate-50'\n              }`}\n            >\n              <div \n                className=\"flex-1 flex gap-2.5 items-start cursor-pointer\"\n                onClick={() => onSelect(ad.address, ad.id)}\n              >\n                <div className=\"p-2 bg-emerald-100/60 rounded-xl mt-0.5 shrink-0\">\n                  {getLabelIcon(ad.label)}\n                </div>\n                <div>\n                  <h4 className=\"font-extrabold text-xs text-slate-800 flex items-center gap-1.5 leading-none\">\n                    {ad.label}\n                    {isActive && (\n                      <span className=\"text-[8px] bg-emerald-600 text-white font-black uppercase rounded px-1 py-px tracking-wider\">\n                        Active\n                      </span>\n                    )}\n                  </h4>\n                  <p className=\"text-[11px] text-slate-500 mt-1 leading-normal pr-8\">\n                    {ad.address}\n                  </p>\n                </div>\n              </div>\n\n              {/* Delete */}\n              {savedAddresses.length > 1 && (\n                <button\n                  onClick={() => onDelete(ad.id)}\n                  className=\"absolute right-2.5 top-1/2 -translate-y-1/2 p-2 rounded-xl text-slate-400 hover:text-red-500 hover:bg-red-50 transition cursor-pointer\"\n                  title=\"Remove Address\"\n                >\n                  <Trash2 className=\"w-4 h-4\" />\n                </button>\n              )}\n            </div>\n          );\n        })}\n      </div>\n\n      {/* Form Trigger Toggle */}\n      {!showForm ? (\n        <button\n          onClick={() => setShowForm(true)}\n          className=\"w-full py-2.5 bg-slate-50 hover:bg-slate-100 text-slate-600 border border-dashed border-slate-250 font-black rounded-xl text-xs flex items-center justify-center gap-1.5 transition cursor-pointer\"\n        >\n          <Plus className=\"w-4 h-4 text-slate-400\" /> Save New Address Location\n        </button>\n      ) : (\n        <form onSubmit={handleSubmit} className=\"p-4 bg-slate-50 rounded-2xl border border-slate-200 space-y-3\">\n          <h4 className=\"text-xs font-black text-slate-700 uppercase\">Enter Destination Point</h4>\n          \n          <div className=\"space-y-1.5\">\n            <span className=\"text-[10px] font-bold text-slate-400 uppercase\">Label:</span>\n            <div className=\"flex flex-wrap gap-1\">\n              {presets.map((p) => (\n                <button\n                  key={p}\n                  type=\"button\"\n                  onClick={() => setNewLabel(p)}\n                  className={`px-2 py-1 rounded text-[11px] font-bold border ${\n                    newLabel === p \n                      ? 'bg-emerald-600 border-emerald-600 text-white' \n                      : 'bg-white border-slate-200 text-slate-700 hover:bg-slate-50'\n                  }`}\n                >\n                  {p}\n                </button>\n              ))}\n              <button\n                type=\"button\"\n                onClick={() => setNewLabel('Custom')}\n                className={`px-2 py-1 rounded text-[11px] font-bold border ${\n                  newLabel === 'Custom' \n                    ? 'bg-emerald-600 border-emerald-600 text-white' \n                    : 'bg-white border-slate-200 text-slate-700 hover:bg-slate-50'\n                }`}\n              >\n                Custom Label\n              </button>\n            </div>\n          </div>\n\n          {newLabel === 'Custom' && (\n            <div className=\"space-y-1\">\n              <input\n                type=\"text\"\n                placeholder=\"Enter custom tag (e.g. 'Hostel', 'Office Tower')\"\n                value={customLabel}\n                onChange={(e) => setCustomLabel(e.target.value)}\n                className=\"w-full bg-white px-2.5 py-1.5 border border-slate-200 rounded-lg text-xs\"\n                required\n              />\n            </div>\n          )}\n\n          <div className=\"space-y-1\">\n            <span className=\"text-[10px] font-bold text-slate-400 uppercase\">Complete Address details:</span>\n            <textarea\n              placeholder=\"e.g. H.No 5-2/12, Main Road, Mahabubabad, Telangana\"\n              value={newAddress}\n              onChange={(e) => setNewAddress(e.target.value)}\n              className=\"w-full bg-white px-2.5 py-1.5 border border-slate-250 rounded-lg text-xs h-16 focus:ring-1 focus:ring-emerald-500 outline-none\"\n              required\n            />\n          </div>\n\n          <div className=\"flex gap-2\">\n            <button\n              type=\"submit\"\n              className=\"px-4 py-2 bg-emerald-600 hover:bg-emerald-700 text-white text-xs font-black rounded-lg transition\"\n            >\n              Save Address\n            </button>\n            <button\n              type=\"button\"\n              onClick={() => setShowForm(false)}\n              className=\"px-4 py-2 bg-slate-200 text-slate-600 rounded-lg text-xs font-bold\"\n            >\n              Cancel\n            </button>\n          </div>\n        </form>\n      )}\n    </div>\n  );\n}\n","import React, { useState, useEffect } from 'react';\nimport { motion, AnimatePresence } from 'motion/react';\nimport { \n  ArrowLeft, \n  CreditCard, \n  MapPin, \n  ShoppingBag, \n  Truck, \n  Gift, \n  Check, \n  ShieldCheck, \n  Lock, \n  Key,\n  AlertCircle,\n  Wallet,\n  Sparkles,\n  AlertTriangle,\n  FileText,\n  Download,\n  RotateCcw,\n  RefreshCw,\n  X,\n  Receipt,\n  BookOpen,\n  Copy,\n  Info\n} from 'lucide-react';\nimport { CartItem } from '../types';\n\ninterface AddressItem {\n  id: string;\n  label: string;\n  address: string;\n}\n\ninterface CheckoutPageProps {\n  cart: CartItem[];\n  subtotal: number;\n  deliveryFee: number;\n  originalDiscount: number; // default discount (from automatic platform rewards)\n  savedAddresses: AddressItem[];\n  activeAddressId: string | null;\n  onPlaceOrder: (\n    address: string, \n    paymentMethod: string, \n    couponApplied: string | null, \n    finalDiscount: number,\n    paymentStatus?: string,\n    transactionId?: string,\n    deliveryInstructions?: string,\n    deliveryTip?: number\n  ) => Promise<any>;\n  onBack: () => void;\n  triggerNotification: (title: string, message: string, type: 'info' | 'success' | 'warning' | 'promo') => void;\n  walletBalance?: number;\n  onTopUpWallet?: (amount: number, gateway: string, gatewayStatus: string) => Promise<any>;\n  deliveryInstructions: string;\n  setDeliveryInstructions: (instructions: string) => void;\n}\n\nexport default function CheckoutPage({\n  cart,\n  subtotal,\n  deliveryFee,\n  originalDiscount,\n  savedAddresses,\n  activeAddressId,\n  onPlaceOrder,\n  onBack,\n  triggerNotification,\n  walletBalance = 1000,\n  onTopUpWallet,\n  deliveryInstructions,\n  setDeliveryInstructions\n}: CheckoutPageProps) {\n  \n  // Choose address\n  const activeAddressObj = savedAddresses.find(a => a.id === activeAddressId) || savedAddresses[0];\n  const [selectedAddress, setSelectedAddress] = useState(activeAddressObj?.address || '');\n\n  useEffect(() => {\n    const freshAddressObj = savedAddresses.find(a => a.id === activeAddressId) || savedAddresses[0];\n    if (freshAddressObj?.address) {\n      setSelectedAddress(freshAddressObj.address);\n    } else {\n      setSelectedAddress('');\n    }\n  }, [activeAddressId, savedAddresses]);\n  const [paymentMethod, setPaymentMethod] = useState<'COD' | 'UPI' | 'CREDIT_CARD' | 'DEBIT_CARD' | 'ONLINE' | 'WALLET' | 'RAZORPAY'>('COD');\n\n  // Coupon state\n  const [couponCode, setCouponCode] = useState('');\n  const [appliedCoupon, setAppliedCoupon] = useState<string | null>(null);\n  const [couponDiscount, setCouponDiscount] = useState<number>(0);\n  const [couponError, setCouponError] = useState<string | null>(null);\n  const [couponSuccess, setCouponSuccess] = useState<string | null>(null);\n  const [dbCoupons, setDbCoupons] = useState<any[]>([]);\n\n  useEffect(() => {\n    const fetchDbCoupons = async () => {\n      try {\n        const res = await fetch('/api/coupons');\n        if (res.ok) {\n          const data = await res.json();\n          setDbCoupons(data);\n        }\n      } catch (err) {\n        console.warn('Failed loading coupons database:', err);\n      }\n    };\n    fetchDbCoupons();\n  }, []);\n\n  // Online Card details (Stripe layout)\n  const [cardNumber, setCardNumber] = useState('');\n  const [cardExpiry, setCardExpiry] = useState('');\n  const [cardCvv, setCardCvv] = useState('');\n  const [cardHolder, setCardHolder] = useState('');\n  const [cardZip, setCardZip] = useState('');\n  const [isCardFlipped, setIsCardFlipped] = useState(false);\n\n  // Razorpay simulated portal state\n  const [showRazorpayModal, setShowRazorpayModal] = useState(false);\n  const [razorpayMethod, setRazorpayMethod] = useState<'CARD' | 'UPI' | 'NET_BANKING'>('UPI');\n  const [upiId, setUpiId] = useState('');\n  const [razorpaySuccessSimulate, setRazorpaySuccessSimulate] = useState(true);\n\n  // Stripe 3DS verification state\n  const [showStripe3DS, setShowStripe3DS] = useState(false);\n  const [stripeSuccessSimulate, setStripeSuccessSimulate] = useState(true);\n  const [stripe3dsCode, setStripe3dsCode] = useState('1234');\n\n  // Interactive topup panel inside Wallet\n  const [walletTopUpOpen, setWalletTopUpOpen] = useState(false);\n  const [topUpAmount, setTopUpAmount] = useState('500');\n  const [topUpGateway, setTopUpGateway] = useState<'Razorpay' | 'Stripe'>('Razorpay');\n  const [topUpSimulateSuccess, setTopUpSimulateSuccess] = useState(true);\n  const [isToppingUp, setIsToppingUp] = useState(false);\n\n  // Checkout states\n  const [deliveryTip, setDeliveryTip] = useState<number>(0);\n  const [isSubmittingOrder, setIsSubmittingOrder] = useState(false);\n  const [paymentError, setPaymentError] = useState<{ code: string; message: string; gateway: string } | null>(null);\n  const [placedOrder, setPlacedOrder] = useState<any>(null);\n  const [showReceiptDetail, setShowReceiptDetail] = useState(false);\n  const [successForwardTimer, setSuccessForwardTimer] = useState(9);\n\n  // Sync address changes\n  useEffect(() => {\n    if (activeAddressObj) {\n      setSelectedAddress(activeAddressObj.address);\n    }\n  }, [activeAddressId, activeAddressObj]);\n\n  // Forward Countdown timer on Success\n  useEffect(() => {\n    if (!placedOrder) return;\n    if (successForwardTimer <= 0) {\n      // Automatic close or view tracking\n      return;\n    }\n    const t = setInterval(() => {\n      setSuccessForwardTimer(prev => prev - 1);\n    }, 1000);\n    return () => clearInterval(t);\n  }, [placedOrder, successForwardTimer]);\n\n  // Format Card Number\n  const handleCardNumberChange = (e: React.ChangeEvent<HTMLInputElement>) => {\n    const val = e.target.value.replace(/\\D/g, '');\n    const matched = val.match(/.{1,4}/g);\n    const formatted = matched ? matched.join(' ').substring(0, 19) : val;\n    setCardNumber(formatted);\n  };\n\n  // Format Expiry\n  const handleExpiryChange = (e: React.ChangeEvent<HTMLInputElement>) => {\n    const val = e.target.value.replace(/\\D/g, '');\n    let formatted = val;\n    if (val.length > 2) {\n      formatted = `${val.substring(0, 2)}/${val.substring(2, 4)}`;\n    }\n    setCardExpiry(formatted.substring(0, 5));\n  };\n\n  const applyCoupon = () => {\n    setCouponError(null);\n    setCouponSuccess(null);\n    const inputCode = couponCode.trim().toUpperCase();\n\n    if (!inputCode) {\n      setCouponError(\"Please type a coupon code first.\");\n      return;\n    }\n\n    // Try dynamic matches from active campaign list first\n    const dynamicMatch = dbCoupons.find(c => c.code === inputCode && c.isActive !== false);\n    if (dynamicMatch) {\n      if (subtotal < dynamicMatch.minOrderValue) {\n        setCouponError(`${dynamicMatch.code} requires a minimum order value of ₹${dynamicMatch.minOrderValue}.`);\n        return;\n      }\n\n      const discountValue = Number(dynamicMatch.discountValue);\n      let calculatedSaved = 0;\n      if (dynamicMatch.discountType === 'percentage') {\n        calculatedSaved = Math.round(subtotal * (discountValue / 100));\n      } else {\n        calculatedSaved = discountValue;\n      }\n\n      setAppliedCoupon(dynamicMatch.code);\n      setCouponDiscount(calculatedSaved);\n      setCouponSuccess(`${dynamicMatch.code} applied! Saved ₹${calculatedSaved} on this basket.`);\n      triggerNotification(\"Coupon Applied 🎉\", `${dynamicMatch.code} is active. Saving ₹${calculatedSaved}!`, \"success\");\n      setCouponCode('');\n      return;\n    }\n\n    // Static fallback options\n    if (inputCode === 'FAST50') {\n      if (subtotal < 200) {\n        setCouponError(\"FAST50 requires a minimum order value of ₹200.\");\n        return;\n      }\n      setAppliedCoupon('FAST50');\n      setCouponDiscount(50);\n      setCouponSuccess(\"FAST50 applied successfully! Saved ₹50 flat.\");\n      triggerNotification(\"Coupon Applied 🎉\", \"FAST50 coupon code unlocked ₹50 discount!\", \"success\");\n    } else if (inputCode === 'FRESH10') {\n      if (subtotal < 150) {\n        setCouponError(\"FRESH10 requires a minimum order value of ₹150.\");\n        return;\n      }\n      setAppliedCoupon('FRESH10');\n      const pctDiscount = Math.round(subtotal * 0.10);\n      setCouponDiscount(pctDiscount);\n      setCouponSuccess(`FRESH10 applied! Saved 10% (₹${pctDiscount}) on fresh greens.`);\n      triggerNotification(\"10% Saved!\", \"FRESH10 coupon code applied successfully.\", \"success\");\n    } else if (inputCode === 'VIPDELIVERY') {\n      setAppliedCoupon('VIPDELIVERY');\n      setCouponDiscount(deliveryFee);\n      setCouponSuccess(\"VIPDELIVERY code accepted! Standard delivery fees waived off entirely.\");\n      triggerNotification(\"Free Deliveries wavered 🛵\", \"You saved ₹25 on delivery fees.\", \"success\");\n    } else {\n      setCouponError(\"Oops! Code not found in dynamic registry or fallbacks.\");\n    }\n    setCouponCode('');\n  };\n\n  const removeCoupon = () => {\n    setAppliedCoupon(null);\n    setCouponDiscount(0);\n    setCouponSuccess(null);\n    setCouponError(null);\n  };\n\n  // Sum total\n  const finalDiscount = originalDiscount + couponDiscount;\n  const netTotal = Math.max(0, subtotal + deliveryFee + deliveryTip - finalDiscount);\n\n  // Trigger wallet top up request\n  const handleWalletTopUpSubmit = async (e: React.FormEvent) => {\n    e.preventDefault();\n    const amount = Number(topUpAmount);\n    if (isNaN(amount) || amount <= 0) {\n      alert(\"Please specify a valid numeric amount to top up.\");\n      return;\n    }\n\n    setIsToppingUp(true);\n    try {\n      if (onTopUpWallet) {\n        const topupStatus = topUpSimulateSuccess ? 'success' : 'failed';\n        await onTopUpWallet(amount, topUpGateway, topupStatus);\n        \n        if (topUpSimulateSuccess) {\n          triggerNotification(\"Wallet Credited 💳\", `Successfully added ₹${amount} using simulated ${topUpGateway} channel!`, \"success\");\n          setWalletTopUpOpen(false);\n          setPaymentError(null);\n        } else {\n          triggerNotification(\"Top-up Failed ❌\", `Simulated top-up through ${topUpGateway} was canceled by user/gateway.`, \"warning\");\n          alert(`Simulated Transaction Failed: Bank server responded with status \"REJECTED_BY_ISSUING_BANK\" over ${topUpGateway}.`);\n        }\n      }\n    } catch (err: any) {\n      alert(\"Failed top up wallet transaction: \" + err.message);\n    } finally {\n      setIsToppingUp(false);\n    }\n  };\n\n  // Main payment processing execution\n  const handleCheckoutSubmit = async (e: React.FormEvent) => {\n    e.preventDefault();\n    setPaymentError(null);\n\n    if (!selectedAddress.trim()) {\n      alert(\"Please select or enter a valid shipping destination.\");\n      return;\n    }\n\n    if (paymentMethod === 'UPI') {\n      if (!upiId.trim() || !upiId.includes('@')) {\n        alert(\"Please enter a valid UPI ID (e.g. name@upi)\");\n        return;\n      }\n      setIsSubmittingOrder(true);\n      try {\n        const generatedTx = 'upi_' + Math.random().toString(36).substring(2, 10) + Math.floor(1000 + Math.random()*9000);\n        const order = await onPlaceOrder(selectedAddress, 'UPI', appliedCoupon, finalDiscount, 'success', generatedTx, deliveryInstructions, deliveryTip);\n        setPlacedOrder(order || { id: 'SC-' + Math.floor(100000 + Math.random() * 900000), total: netTotal, createdAt: new Date().toISOString() });\n        triggerNotification(\"Order Confirmed 🎉\", \"Paid using UPI ID \" + upiId + \" instantly!\", \"success\");\n      } catch (err: any) {\n        setPaymentError({\n          code: 'UPI_COLLECT_FAILED',\n          message: err.message || \"Failed to process UPI payment collect request.\",\n          gateway: 'UPI Secure'\n        });\n      } finally {\n        setIsSubmittingOrder(false);\n      }\n    } \n    else if (paymentMethod === 'COD') {\n      setIsSubmittingOrder(true);\n      try {\n        const order = await onPlaceOrder(selectedAddress, 'COD', appliedCoupon, finalDiscount, 'pending', undefined, deliveryInstructions, deliveryTip);\n        setPlacedOrder(order || { id: 'SC-' + Math.floor(100000 + Math.random() * 900000), total: netTotal, createdAt: new Date().toISOString() });\n        triggerNotification(\"Order Booked (COD) 📦\", \"Pay ₹\" + netTotal + \" directly to the delivery rider.\", \"success\");\n      } catch (err: any) {\n        alert(\"Failed to register cash-on-delivery order: \" + err.message);\n      } finally {\n        setIsSubmittingOrder(false);\n      }\n    } else if (paymentMethod === 'CREDIT_CARD' || paymentMethod === 'DEBIT_CARD') {\n      // Validate Card Form fields\n      if (cardNumber.replace(/\\s/g, '').length < 16) {\n        alert(\"Please complete the 16-digit card input.\");\n        return;\n      }\n      if (cardExpiry.length < 5) {\n        alert(\"Please complete card expiration MM/YY.\");\n        return;\n      }\n      if (cardCvv.length < 3) {\n        alert(\"Please provide the card secure CVV.\");\n        return;\n      }\n      if (!cardHolder.trim()) {\n        alert(\"Please enter the Cardholder Name.\");\n        return;\n      }\n      \n      // Open simulated Stripe 3DS iframe modal\n      setShowStripe3DS(true);\n    }\n  };\n\n  // Triggered when Stripe 3D-Secure complete\n  const handleStripeMockComplete = async () => {\n    setShowStripe3DS(false);\n    if (!stripeSuccessSimulate) {\n      setPaymentError({\n        code: 'CARD_SECURITY_FAIL',\n        message: \"Cardholder authentication verification failed. Reason: [CVV_EXPIRED] Expired or invalid CVV security configuration.\",\n        gateway: 'Secure Pay'\n      });\n      triggerNotification(\"Card Declined 💳\", \"Credit card failed verification checkout. Please check parameters.\", \"warning\");\n      return;\n    }\n\n    setIsSubmittingOrder(true);\n    try {\n      const cardTypeLabel = paymentMethod === 'CREDIT_CARD' ? 'Credit Card' : 'Debit Card';\n      const generatedTx = 'ch_' + Math.random().toString(36).substring(2, 12);\n      const order = await onPlaceOrder(selectedAddress, cardTypeLabel, appliedCoupon, finalDiscount, 'success', generatedTx, deliveryInstructions, deliveryTip);\n      setPlacedOrder(order || { id: 'SC-' + Math.floor(100000 + Math.random() * 900000), total: netTotal, createdAt: new Date().toISOString() });\n      triggerNotification(`${cardTypeLabel} Verified ⚡️`, \"Transaction completed successfully!\", \"success\");\n    } catch (err: any) {\n      setPaymentError({\n        code: 'CARD_CAPTURE_FAILED',\n        message: err.message || \"Card capture was declined by card network.\",\n        gateway: 'Stripe'\n      });\n    } finally {\n      setIsSubmittingOrder(false);\n    }\n  };\n\n  // Auto recognizer for card logos\n  const getCardLogo = () => {\n    if (cardNumber.startsWith('4')) return 'VISA';\n    if (cardNumber.startsWith('5')) return 'MASTERCARD';\n    if (cardNumber.startsWith('3')) return 'AMEX';\n    return 'CARD';\n  };\n\n  return (\n    <div id=\"checkout-view-panel\" className=\"max-w-2xl mx-auto space-y-4\">\n      \n      {/* 1. SUCCESS OVERLAY INVOICE (No unrequested features - directly handles the requested feature of Payment Success Page!) */}\n      {placedOrder ? (\n        <div className=\"bg-white rounded-3xl p-6 border border-slate-150 shadow-2xl text-center space-y-6 pt-10 pb-8 animate-fade-in text-slate-800\">\n          \n          {/* Animated celebration icon */}\n          <div className=\"relative w-20 h-20 mx-auto\">\n            <motion.div \n              initial={{ scale: 0.3, opacity: 0 }}\n              animate={{ scale: [1, 1.15, 1], opacity: 1 }}\n              transition={{ duration: 0.5 }}\n              className=\"w-20 h-20 bg-emerald-50 rounded-full flex items-center justify-center text-emerald-600 border border-emerald-100 z-10\"\n            >\n              <Check className=\"w-10 h-10 stroke-[3]\" />\n            </motion.div>\n            \n            {/* Ambient Sparkles */}\n            <span className=\"absolute -top-1 -left-2 text-yellow-500 text-lg animate-spin\">✨</span>\n            <span className=\"absolute top-8 -right-3 text-amber-500 text-xs animate-bounce\">⚡️</span>\n            <span className=\"absolute -bottom-2 left-6 text-emerald-500 text-base animate-pulse\">🎉</span>\n          </div>\n\n          <div className=\"space-y-1.5 max-w-sm mx-auto\">\n            <h2 className=\"text-lg font-black text-slate-900 tracking-tight uppercase\">Payment Completed Successfully!</h2>\n            <p className=\"text-[11px] text-slate-400 font-semibold leading-relaxed\">\n              Your account was billed <span className=\"font-bold text-slate-700 font-mono\">₹{netTotal}</span> using <span className=\"font-black text-slate-700 uppercase bg-slate-100 px-1.5 py-0.5 rounded text-[10px]\">{paymentMethod === 'ONLINE' ? 'Stripe Gateway' : paymentMethod}</span>. Here is your tracking receipt.\n            </p>\n          </div>\n\n          {/* Reference transaction detail box */}\n          <div className=\"bg-slate-50 border border-slate-150 rounded-2xl p-4 text-xs space-y-2 text-left max-w-md mx-auto\">\n            <div className=\"flex justify-between\">\n              <span className=\"text-slate-400 font-bold uppercase text-[9px]\">Registered Order:</span>\n              <span className=\"font-extrabold text-slate-800 font-mono\">#{placedOrder.id}</span>\n            </div>\n            \n            {placedOrder.transactionId && (\n              <div className=\"flex justify-between\">\n                <span className=\"text-slate-400 font-bold uppercase text-[9px]\">Transaction Ref:</span>\n                <span className=\"font-mono text-[10px] text-emerald-700 flex items-center gap-1\">\n                  {placedOrder.transactionId}\n                  <span className=\"text-[8px] bg-emerald-100 text-emerald-800 font-bold px-1 rounded uppercase\">PAID</span>\n                </span>\n              </div>\n            )}\n\n            <div className=\"flex justify-between border-t border-slate-100 pt-2 text-slate-500\">\n              <span>Delivery Eta Hub:</span>\n              <span className=\"font-bold text-slate-700 font-medium\">🛵 Express (<span className=\"text-emerald-600\">10 Mins</span>)</span>\n            </div>\n\n            <div className=\"flex justify-between text-slate-500\">\n              <span className=\"\">Destination drop address:</span>\n              <span className=\"font-semibold text-slate-600 truncate max-w-[200px]\">{selectedAddress}</span>\n            </div>\n          </div>\n\n          {/* Interactive invoice breakdown toggle */}\n          <div className=\"max-w-md mx-auto space-y-2\">\n            <button\n              onClick={() => setShowReceiptDetail(!showReceiptDetail)}\n              className=\"text-xs text-slate-500 hover:text-emerald-600 font-bold flex items-center gap-1.5 mx-auto py-1.5 px-3 rounded-lg bg-slate-100 hover:bg-slate-200 cursor-pointer\"\n            >\n              <Receipt className=\"w-3.5 h-3.5\" />\n              {showReceiptDetail ? 'Hide Detailed Grocery Receipt' : 'Expand Grocery Receipt Breakdown'}\n            </button>\n\n            {showReceiptDetail && (\n              <motion.div \n                initial={{ opacity: 0, y: -10 }}\n                animate={{ opacity: 1, y: 0 }}\n                className=\"bg-white border rounded-2xl p-4 text-left text-xs space-y-3 shadow-inner\"\n              >\n                <div className=\"border-b pb-2 font-bold text-[10px] text-slate-400 uppercase tracking-wider flex justify-between\">\n                  <span>Grocery Item</span>\n                  <span>Qty • Total</span>\n                </div>\n                \n                <div className=\"space-y-2 max-h-40 overflow-y-auto\">\n                  {cart.map((item, idx) => (\n                    <div key={idx} className=\"flex justify-between text-slate-700 text-[11px]\">\n                      <span>{item.product?.name || 'Deleted Product'} <span className=\"text-slate-400\">({item.product?.unit || '1 unit'})</span></span>\n                      <span className=\"font-mono text-slate-800 font-bold\">x{item.quantity} • ₹{(item.product?.price || 0) * item.quantity}</span>\n                    </div>\n                  ))}\n                </div>\n\n                <div className=\"border-t border-dashed pt-2 space-y-1.5 text-[11px] text-slate-500\">\n                  <div className=\"flex justify-between\">\n                    <span>Items Subtotal:</span>\n                    <span className=\"font-mono\">₹{subtotal}</span>\n                  </div>\n                  <div className=\"flex justify-between\">\n                    <span>Delivery Fee:</span>\n                    <span>₹{deliveryFee}</span>\n                  </div>\n                  {deliveryTip > 0 && (\n                    <div className=\"flex justify-between text-emerald-700 font-semibold bg-emerald-500/5 px-1.5 py-0.5 rounded-lg\">\n                      <span>Rider Delivery Tip 💝:</span>\n                      <span className=\"font-mono font-bold\">₹{deliveryTip}</span>\n                    </div>\n                  )}\n                  {finalDiscount > 0 && (\n                    <div className=\"flex justify-between text-emerald-600 font-bold\">\n                      <span>Reward / Coupons code off:</span>\n                      <span className=\"font-mono\">-₹{finalDiscount}</span>\n                    </div>\n                  )}\n                  <div className=\"flex justify-between text-slate-800 font-black pt-1.5 border-t\">\n                    <span>Net Paid Amount:</span>\n                    <span className=\"font-mono text-base text-emerald-700\">₹{netTotal}</span>\n                  </div>\n                </div>\n\n                {/* Simulate invoice downloading PDF */}\n                <button\n                  onClick={() => {\n                    alert(\"DOWNLOADING INVOICE... Simulated PDF file downloaded: dailymart_invoice_\" + placedOrder.id + \".pdf\");\n                  }}\n                  className=\"w-full mt-2 py-1.5 bg-slate-900 text-white font-extrabold text-[10px] rounded-lg tracking-wider hover:bg-slate-800 uppercase flex items-center justify-center gap-1.5\"\n                >\n                  <Download className=\"w-3.5 h-3.5\" /> Download Digital PDF Invoice Receipt\n                </button>\n              </motion.div>\n            )}\n          </div>\n\n          <div className=\"h-px bg-slate-100 my-4 max-w-md mx-auto\"></div>\n\n          {/* Action buttons */}\n          <div className=\"space-y-3 max-w-sm mx-auto\">\n            <button\n              onClick={onBack}\n              className=\"w-full bg-emerald-600 hover:bg-emerald-700 text-white font-black py-3 rounded-2xl flex items-center justify-center gap-1.5 shadow-md cursor-pointer text-xs uppercase cursor-pointer\"\n            >\n              🚀 Track Live Store Dispatch Progress Now ({successForwardTimer}s)\n            </button>\n            <p className=\"text-[10px] text-slate-400 font-semibold italic\">or press the Back button inside workspace to return immediately</p>\n          </div>\n\n        </div>\n      ) : (\n        <div id=\"checkout-main-grid\" className=\"space-y-4\">\n          \n          {/* Nav Header */}\n          <div className=\"flex items-center justify-between bg-white rounded-2xl p-3.5 border border-slate-100 shadow-xs\">\n            <button\n              onClick={onBack}\n              className=\"flex items-center gap-1 text-slate-500 hover:text-emerald-600 font-bold text-xs cursor-pointer\"\n            >\n              <ArrowLeft className=\"w-4 h-4\" /> Cancel & Back to Cart\n            </button>\n            <span className=\"text-xs font-black tracking-widest text-[#10b981] uppercase flex items-center gap-1 font-mono\">\n              <ShieldCheck className=\"w-4 h-4\" /> SECURE CHECKOUT SSL\n            </span>\n          </div>\n\n          {/* 2. DYNAMIC FAILED PAYMENT DIAGNOSTICS CARD */}\n          {paymentError && (\n            <motion.div \n              initial={{ scale: 0.95, opacity: 0 }}\n              animate={{ scale: 1, opacity: 1 }}\n              className=\"p-4 bg-rose-50 border border-rose-200/80 rounded-2xl space-y-3 text-left shadow-md\"\n            >\n              <div className=\"flex items-start gap-2.5 text-rose-800\">\n                <AlertTriangle className=\"w-5 h-5 text-rose-600 shrink-0 mt-0.5\" />\n                <div className=\"space-y-1\">\n                  <h4 className=\"text-xs font-black uppercase tracking-wider\">Payment Transaction Failure</h4>\n                  <p className=\"text-[11px] font-semibold text-rose-700 leading-normal\">{paymentError.message}</p>\n                </div>\n              </div>\n\n              <div className=\"bg-white/80 border border-rose-100 rounded-xl p-2.5 px-3 text-[10px] font-mono text-rose-800 space-y-1\">\n                <div>Source Gateway: <span className=\"font-extrabold\">{paymentError.gateway}</span></div>\n                <div>Declined Code: <span className=\"font-extrabold\">{paymentError.code}</span></div>\n                <div>Status Reason: <span className=\"italic\">Customer security clearance decline or client balance depletion.</span></div>\n              </div>\n\n              <div className=\"flex gap-2\">\n                <button\n                  type=\"button\"\n                  onClick={() => {\n                    setPaymentMethod('COD');\n                    setPaymentError(null);\n                  }}\n                  className=\"px-3 py-1.5 bg-rose-800 hover:bg-rose-900 text-white rounded-xl text-[10px] font-black uppercase cursor-pointer\"\n                >\n                  Switch pay method to COD\n                </button>\n                \n                {paymentMethod === 'WALLET' && (\n                  <button\n                    type=\"button\"\n                    onClick={() => {\n                      setWalletTopUpOpen(true);\n                      setPaymentError(null);\n                    }}\n                    className=\"px-3 py-1.5 bg-emerald-700 hover:bg-emerald-800 text-white rounded-xl text-[10px] font-black uppercase cursor-pointer\"\n                  >\n                    Quick Wallet Top-up\n                  </button>\n                )}\n\n                <button\n                  type=\"button\"\n                  onClick={() => setPaymentError(null)}\n                  className=\"px-3 py-1.5 bg-slate-200 text-slate-700 hover:bg-slate-350 rounded-xl text-[10px] font-extrabold uppercase cursor-pointer\"\n                >\n                  Dismiss error\n                </button>\n              </div>\n            </motion.div>\n          )}\n\n          <form onSubmit={handleCheckoutSubmit} className=\"space-y-4 text-left\">\n            {/* Step 1: Destination location */}\n            <div className=\"bg-white rounded-3xl p-5 border border-slate-100 shadow-xs space-y-3\">\n              <div className=\"flex items-center gap-2 text-slate-800 font-bold border-b border-slate-50 pb-2\">\n                <MapPin className=\"w-4.5 h-4.5 text-emerald-600\" />\n                <h3 className=\"text-xs font-black text-slate-700 uppercase tracking-wide\">1. Shipping Destination Location</h3>\n              </div>\n              \n              <div className=\"space-y-2\">\n                <span className=\"text-[10px] text-slate-400 font-bold uppercase block\">Selected drop address point:</span>\n                <textarea\n                  value={selectedAddress}\n                  onChange={(e) => setSelectedAddress(e.target.value)}\n                  className=\"w-full bg-slate-50 text-slate-800 p-2.5 rounded-xl border border-slate-200 text-xs focus:ring-1 focus:ring-emerald-500 outline-none leading-normal font-medium h-16\"\n                  placeholder=\"e.g. H.No 5-2/12, Main Road, Mahabubabad, Telangana\"\n                  required\n                />\n                {savedAddresses.length > 0 && (\n                  <div className=\"flex flex-wrap gap-1.5 mt-2\">\n                    <span className=\"text-[9px] font-black text-slate-400 uppercase mt-1\">Quick Select:</span>\n                    {savedAddresses.map((ad) => (\n                      <button\n                        key={ad.id}\n                        type=\"button\"\n                        onClick={() => setSelectedAddress(ad.address)}\n                        className={`px-2 py-0.5 rounded text-[10px] font-black border uppercase transition duration-100 cursor-pointer ${\n                          selectedAddress === ad.address\n                            ? 'bg-emerald-600 border-emerald-600 text-white'\n                            : 'bg-slate-100 border-slate-200 text-slate-600 hover:bg-slate-150'\n                        }`}\n                      >\n                        {ad.label}\n                      </button>\n                    ))}\n                  </div>\n                )}\n              </div>\n\n              <div className=\"space-y-2 pt-2 border-t border-slate-100\">\n                <span className=\"text-[10px] text-slate-400 font-bold uppercase block\">Delivery Instructions for Rider 🛵:</span>\n                <input\n                  type=\"text\"\n                  value={deliveryInstructions}\n                  onChange={(e) => setDeliveryInstructions(e.target.value)}\n                  className=\"w-full bg-slate-50 text-slate-800 p-2.5 rounded-xl border border-slate-200 text-xs focus:ring-1 focus:ring-emerald-500 outline-none leading-normal font-medium\"\n                  placeholder=\"e.g. Leave at the gate, call upon arrival, etc.\"\n                />\n              </div>\n            </div>\n\n            {/* Step 2: Promo Coupons discount section */}\n            <div className=\"bg-white rounded-3xl p-5 border border-slate-100 shadow-xs space-y-3\">\n              <div className=\"flex items-center gap-2 text-slate-800 font-bold border-b border-slate-50 pb-2\">\n                <Gift className=\"w-4.5 h-4.5 text-emerald-600\" />\n                <h3 className=\"text-xs font-black text-slate-700 uppercase tracking-wide\">2. Apply Reward Discount Code</h3>\n              </div>\n\n              <div className=\"space-y-2\">\n                {!appliedCoupon ? (\n                  <div className=\"flex gap-2\">\n                    <input\n                      type=\"text\"\n                      placeholder=\"Promo Code (FAST50, FRESH10, VIPDELIVERY)\"\n                      value={couponCode}\n                      onChange={(e) => setCouponCode(e.target.value)}\n                      className=\"bg-slate-50 text-slate-800 flex-1 px-3 py-2 border border-slate-250 rounded-xl uppercase font-black tracking-wider text-xs focus:ring-1 focus:ring-emerald-500 outline-none\"\n                    />\n                    <button\n                      type=\"button\"\n                      onClick={applyCoupon}\n                      className=\"px-4 py-2 bg-slate-900 hover:bg-slate-950 text-white border border-slate-900 rounded-xl text-xs font-black transition cursor-pointer\"\n                    >\n                      Apply\n                    </button>\n                  </div>\n                ) : (\n                  <div className=\"p-3 bg-emerald-50 border border-emerald-150 rounded-2xl flex items-center justify-between\">\n                    <div>\n                      <span className=\"text-[10px] bg-emerald-600 text-white font-extrabold rounded px-1.5 py-0.5 uppercase block w-max\">\n                        {appliedCoupon} ACTIVE\n                      </span>\n                      <p className=\"text-[11px] text-emerald-800 font-bold mt-1\">₹{couponDiscount} coupon savings automatically saved!</p>\n                    </div>\n                    <button\n                      type=\"button\"\n                      onClick={removeCoupon}\n                      className=\"text-xs text-red-600 font-bold hover:underline cursor-pointer\"\n                    >\n                      Remove Coupon\n                    </button>\n                  </div>\n                )}\n\n                {/* Error & Success info layouts */}\n                {couponError && (\n                  <p className=\"text-[10px] text-red-500 font-bold flex items-center gap-1 mt-1\">\n                    <AlertCircle className=\"w-3.5 h-3.5\" /> {couponError}\n                  </p>\n                )}\n                {couponSuccess && (\n                  <p className=\"text-[10px] text-emerald-600 font-bold flex items-center gap-1 mt-1\">\n                    <Check className=\"w-3.5 h-3.5\" /> {couponSuccess}\n                  </p>\n                )}\n\n                {/* Visual Clickable Voucher Deck */}\n                <div className=\"space-y-1.5\">\n                  <span className=\"text-[9px] text-slate-400 font-black uppercase tracking-wider block\">One-Click Available Promos</span>\n                  <div className=\"grid grid-cols-1 sm:grid-cols-3 gap-2.5 pt-0.5\">\n                    {[\n                      { code: 'FAST50', name: '₹50 flat savings', min: 'Min: ₹200', desc: 'On grocery staples', color: 'bg-amber-500/5 hover:bg-amber-500/10 border-amber-500/25 text-amber-900 disabled:opacity-50' },\n                      { code: 'FRESH10', name: '10% on whole cart', min: 'Min: ₹150', desc: 'On fresh greens', color: 'bg-emerald-500/5 hover:bg-emerald-500/10 border-emerald-500/25 text-emerald-900 disabled:opacity-50' },\n                      { code: 'VIPDELIVERY', name: 'Free Express Shipping', min: 'Min: ₹0', desc: 'Zero delivery fee', color: 'bg-sky-500/5 hover:bg-sky-500/10 border-sky-500/25 text-sky-900 disabled:opacity-50' }\n                    ].map((voucher) => (\n                      <button\n                        key={voucher.code}\n                        type=\"button\"\n                        onClick={() => {\n                          setCouponCode(voucher.code);\n                          setTimeout(() => {\n                            const inputCode = voucher.code;\n                            if (inputCode === 'FAST50') {\n                              if (subtotal < 200) {\n                                setCouponError(\"FAST50 requires a minimum order value of ₹200.\");\n                                return;\n                              }\n                              setAppliedCoupon('FAST50');\n                              setCouponDiscount(50);\n                              setCouponSuccess(\"FAST50 applied successfully! Saved ₹50 flat.\");\n                              triggerNotification(\"Coupon Applied 🎉\", \"FAST50 coupon code unlocked ₹50 discount!\", \"success\");\n                              setCouponCode('');\n                            } else if (inputCode === 'FRESH10') {\n                              if (subtotal < 150) {\n                                setCouponError(\"FRESH10 requires a minimum order value of ₹150.\");\n                                return;\n                              }\n                              setAppliedCoupon('FRESH10');\n                              const pctDiscount = Math.round(subtotal * 0.10);\n                              setCouponDiscount(pctDiscount);\n                              setCouponSuccess(`FRESH10 applied! Saved 10% (₹${pctDiscount}) on fresh greens.`);\n                              triggerNotification(\"10% Saved!\", \"FRESH10 coupon code applied successfully.\", \"success\");\n                              setCouponCode('');\n                            } else if (inputCode === 'VIPDELIVERY') {\n                              setAppliedCoupon('VIPDELIVERY');\n                              setCouponDiscount(deliveryFee);\n                              setCouponSuccess(\"VIPDELIVERY code accepted! Standard delivery fees waived off entirely.\");\n                              triggerNotification(\"Free Deliveries waived 🛵\", \"You saved ₹25 on delivery fees.\", \"success\");\n                              setCouponCode('');\n                            }\n                          }, 50);\n                        }}\n                        className={`border border-dashed p-2.5 rounded-xl text-left transition active:scale-95 cursor-pointer relative overflow-hidden flex flex-col justify-between ${voucher.color} h-[85px]`}\n                        disabled={!!appliedCoupon}\n                      >\n                        {/* Ticket scissor cuts decoration */}\n                        <div className=\"absolute top-1/2 -left-1.5 w-3 h-3 rounded-full bg-white border-r border-slate-200 -translate-y-1/2\"></div>\n                        <div className=\"absolute top-1/2 -right-1.5 w-3 h-3 rounded-full bg-white border-l border-slate-200 -translate-y-1/2\"></div>\n\n                        <div className=\"space-y-0.5\">\n                          <div className=\"flex items-center justify-between\">\n                            <span className=\"font-mono font-black text-[9px] tracking-wider text-slate-800 bg-white/80 px-1 py-0.2 rounded border border-slate-200/55\">\n                              {voucher.code}\n                            </span>\n                            <span className=\"text-[7.5px] font-bold opacity-75\">{voucher.min}</span>\n                          </div>\n                          <p className=\"text-[9.5px] font-black tracking-tight leading-tight mt-1\">{voucher.name}</p>\n                        </div>\n                        <p className=\"text-[8px] opacity-60 leading-none truncate\">{voucher.desc}</p>\n                      </button>\n                    ))}\n                  </div>\n                </div>\n\n                <div className=\"bg-slate-50 rounded-xl p-2 px-3 text-[10px] text-slate-500 flex gap-2\">\n                  <span className=\"font-extrabold uppercase text-amber-600 shrink-0\">Available Promos:</span>\n                  <span className=\"font-semibold select-all font-mono\">FAST50 (₹50 off, Min ₹200) • FRESH10 (10% off) • VIPDELIVERY (Free Shipping)</span>\n                </div>\n              </div>\n            </div>\n\n            {/* Step 3: Payment Type selection */}\n            <div className=\"bg-white rounded-3xl p-5 border border-slate-100 shadow-xs space-y-4\">\n              <div className=\"flex items-center gap-2 text-slate-800 font-bold border-b border-slate-50 pb-2\">\n                <CreditCard className=\"w-4.5 h-4.5 text-emerald-600\" />\n                <h3 className=\"text-xs font-black text-slate-700 uppercase tracking-wide\">3. Select Payment Method</h3>\n              </div>\n\n              <div className=\"grid grid-cols-2 gap-3\">\n                \n                {/* 1. Cash on delivery */}\n                <button\n                  type=\"button\"\n                  onClick={() => setPaymentMethod('COD')}\n                  className={`p-3 rounded-2xl text-left border flex flex-col gap-1 cursor-pointer transition ${\n                    paymentMethod === 'COD'\n                      ? 'border-emerald-600 bg-emerald-50/30 text-slate-850'\n                      : 'border-slate-100 hover:bg-slate-50 text-slate-700'\n                  }`}\n                >\n                  <span className=\"font-extrabold text-xs\">Cash on Delivery (COD)</span>\n                  <span className=\"text-[9px] text-slate-400 line-clamp-2\">Pay cash or scan UPI QR-code directly to delivery rider at your doorstep.</span>\n                </button>\n\n                {/* 2. UPI Instant Pay */}\n                <button\n                  type=\"button\"\n                  onClick={() => setPaymentMethod('UPI')}\n                  className={`p-3 rounded-2xl text-left border flex flex-col gap-1 cursor-pointer transition ${\n                    paymentMethod === 'UPI'\n                      ? 'border-emerald-600 bg-emerald-50/30 text-slate-850'\n                      : 'border-slate-100 hover:bg-slate-50 text-slate-700'\n                  }`}\n                >\n                  <div className=\"flex justify-between items-center w-full\">\n                    <span className=\"font-extrabold text-xs text-slate-850\">UPI Instant Pay</span>\n                    <span className=\"text-[8px] tracking-wide bg-emerald-600 text-white font-black px-1 rounded uppercase\">UPI</span>\n                  </div>\n                  <span className=\"text-[9px] text-slate-400 line-clamp-2\">Instant payment redirect using Google Pay, PhonePe, Paytm, or BHIM.</span>\n                </button>\n\n                {/* 3. Credit Card */}\n                <button\n                  type=\"button\"\n                  onClick={() => setPaymentMethod('CREDIT_CARD')}\n                  className={`p-3 rounded-2xl text-left border flex flex-col gap-1 cursor-pointer transition ${\n                    paymentMethod === 'CREDIT_CARD'\n                      ? 'border-indigo-600 bg-indigo-50/30 text-slate-855 font-bold'\n                      : 'border-slate-100 hover:bg-slate-50'\n                  }`}\n                >\n                  <div className=\"flex justify-between items-center w-full\">\n                    <span className=\"font-extrabold text-xs text-slate-800\">Credit Card</span>\n                    <span className=\"text-[8px] tracking-wide bg-indigo-600 text-white font-black px-1 rounded uppercase\">CC</span>\n                  </div>\n                  <span className=\"text-[9px] text-slate-400 line-clamp-2\">Secure transaction via Visa, Mastercard, AMEX with 3D Secure verification.</span>\n                </button>\n\n                {/* 4. Debit Card */}\n                <button\n                  type=\"button\"\n                  onClick={() => setPaymentMethod('DEBIT_CARD')}\n                  className={`p-3 rounded-2xl text-left border flex flex-col gap-1 cursor-pointer transition ${\n                    paymentMethod === 'DEBIT_CARD'\n                      ? 'border-indigo-600 bg-indigo-50/30 text-slate-855 font-bold'\n                      : 'border-slate-100 hover:bg-slate-50'\n                  }`}\n                >\n                  <div className=\"flex justify-between items-center w-full\">\n                    <span className=\"font-extrabold text-xs text-slate-800\">Debit Card</span>\n                    <span className=\"text-[8px] tracking-wide bg-indigo-600 text-white font-black px-1 rounded uppercase\">DC</span>\n                  </div>\n                  <span className=\"text-[9px] text-slate-400 line-clamp-2\">Use RuPay, Visa, Mastercard debit cards with bank authentication page.</span>\n                </button>\n\n              </div>\n\n              {/* UPI ID Info panel */}\n              {paymentMethod === 'UPI' && (\n                <div className=\"p-4 bg-slate-50/60 rounded-2xl border border-slate-150 space-y-3 animate-fade-in text-slate-700\">\n                  <span className=\"text-[10px] uppercase font-black text-slate-400 block tracking-wider\">Enter UPI ID</span>\n                  <div className=\"flex gap-2\">\n                    <input\n                      type=\"text\"\n                      placeholder=\"e.g. mobileNo@ybl, yourname@okhdfcbank\"\n                      value={upiId}\n                      onChange={(e) => setUpiId(e.target.value)}\n                      className=\"bg-white border text-slate-800 border-slate-205 px-3 py-2 text-xs rounded-xl flex-1 focus:ring-1 focus:ring-emerald-500 outline-none animate-none\"\n                    />\n                  </div>\n                  <p className=\"text-[9.5px] text-slate-400 leading-normal\">\n                    You will receive a payment request on your preferred UPI app. Just enter your UPI PIN there to approve the transaction. Common handles: @okaxis, @okhdfcbank, @paytm, @ybl\n                  </p>\n                </div>\n              )}\n\n              {/* Stripe elements card detail block panel */}\n              {(paymentMethod === 'CREDIT_CARD' || paymentMethod === 'DEBIT_CARD') && (\n                <div className=\"p-4 bg-slate-50/60 rounded-2xl border border-slate-150 space-y-4 animate-fade-in text-slate-700\">\n                  <div className=\"flex justify-between items-center\">\n                    <h4 className=\"text-[10px] font-black text-slate-500 uppercase flex items-center gap-1\">\n                      <Lock className=\"w-3.5 h-3.5 text-indigo-600\" /> Secure Card Transaction\n                    </h4>\n                    <span className=\"text-[8px] bg-slate-100 uppercase border font-bold px-1 rounded text-slate-500\">PCIDSS Compliant</span>\n                  </div>\n\n                  {/* HIGH-END INTERACTIVE DEBIT CARD PREVIEW GRAPHICS */}\n                  <div className=\"perspective-1000 max-w-sm mx-auto w-full h-44 cursor-pointer\" onClick={() => setIsCardFlipped(!isCardFlipped)}>\n                    <motion.div \n                      animate={{ rotateY: isCardFlipped ? 180 : 0 }}\n                      transition={{ duration: 0.6 }}\n                      className=\"w-full h-full relative transform-style-3d shadow-xl rounded-2xl\"\n                    >\n                      {/* CARD FRONT SIDE GRAPHIC */}\n                      <div className=\"absolute inset-0 bg-gradient-to-br from-slate-800 to-slate-950 p-4 font-mono text-white rounded-2xl flex flex-col justify-between backface-hidden\">\n                        <div className=\"flex justify-between items-start\">\n                          <div>\n                            <span className=\"text-[8px] text-slate-400 uppercase font-bold block\">Daily Mart Premium Card</span>\n                            <span className=\"text-xs font-black tracking-widest text-emerald-400\">{paymentMethod.replace('_', ' ')}</span>\n                          </div>\n                          \n                          {/* Gold holographic microchip chip */}\n                          <div className=\"w-9 h-7 bg-gradient-to-r from-yellow-300 to-yellow-500 rounded-md border border-yellow-200\"></div>\n                        </div>\n\n                        {/* Interactive formatted card digits */}\n                        <div className=\"text-sm font-black tracking-widest text-center my-4 select-all text-slate-100\">\n                          {cardNumber || '•••• •••• •••• ••••'}\n                        </div>\n\n                        <div className=\"flex justify-between text-left text-[9px] text-slate-400\">\n                          <div>\n                            <span className=\"block text-[7px] text-slate-500 uppercase\">Card Holder Name</span>\n                            <span className=\"font-bold text-slate-200 uppercase truncate max-w-[150px] inline-block\">{cardHolder || 'Your Name'}</span>\n                          </div>\n                          <div className=\"text-right\">\n                            <span className=\"block text-[7px] text-slate-500 uppercase\">Expires End</span>\n                            <span className=\"font-bold text-slate-250 font-mono\">{cardExpiry || 'MM/YY'}</span>\n                          </div>\n                        </div>\n                      </div>\n\n                      {/* CARD BACK SIDE GRAPHIC */}\n                      <div className=\"absolute inset-x-0 inset-y-0 bg-gradient-to-br from-slate-900 to-slate-950 text-white rounded-2xl flex flex-col justify-between backface-hidden [transform:rotateY(180deg)] border-t border-slate-700\">\n                        <div className=\"w-full h-9 bg-slate-800 mt-4\"></div>\n                        \n                        <div className=\"p-4 flex flex-col\">\n                          <label className=\"text-[7px] text-slate-400 uppercase tracking-wider text-right pr-2\">CVV Security Number</label>\n                          <div className=\"flex justify-between items-center bg-slate-100 text-slate-800 px-3 py-1 text-sm text-right rounded font-bold\">\n                            <span className=\"text-xs text-slate-400 font-mono\">Daily signature column check</span>\n                            <span className=\"font-mono text-slate-900\">{cardCvv || '•••'}</span>\n                          </div>\n                        </div>\n\n                        <div className=\"p-3 text-[8px] text-slate-500 text-center font-mono\">\n                          Simulated Card Elements node. Flip back.\n                        </div>\n                      </div>\n\n                    </motion.div>\n                  </div>\n\n                  {/* CARD INPUT FIELDS */}\n                  <div className=\"space-y-3.5 text-xs pt-1\">\n                    <div className=\"grid grid-cols-2 gap-3\">\n                      <div className=\"space-y-1\">\n                        <label className=\"text-[9px] font-black text-slate-400 uppercase\">Cardholder Name</label>\n                        <input\n                          type=\"text\"\n                          placeholder=\"Owner Name\"\n                          value={cardHolder}\n                          onChange={(e) => setCardHolder(e.target.value)}\n                          className=\"w-full bg-white px-3 py-2 border border-slate-250 text-xs rounded-xl focus:ring-1 focus:ring-emerald-500 outline-none\"\n                          required={paymentMethod === 'CREDIT_CARD' || paymentMethod === 'DEBIT_CARD'}\n                        />\n                      </div>\n                      \n                      <div className=\"space-y-1\">\n                        <label className=\"text-[9px] font-black text-slate-400 uppercase\">16-Digit Card Number</label>\n                        <input\n                          type=\"text\"\n                          placeholder=\"4111 2222 3333 4444\"\n                          value={cardNumber}\n                          onChange={handleCardNumberChange}\n                          onFocus={() => setIsCardFlipped(false)}\n                          className=\"w-full bg-white px-3 py-2 border border-slate-250 text-xs rounded-xl focus:ring-1 focus:ring-emerald-500 outline-none font-mono tracking-wider\"\n                          maxLength={19}\n                          required={paymentMethod === 'CREDIT_CARD' || paymentMethod === 'DEBIT_CARD'}\n                        />\n                      </div>\n                    </div>\n\n                    <div className=\"grid grid-cols-3 gap-2.5\">\n                      <div className=\"space-y-1\">\n                        <label className=\"text-[9px] font-black text-slate-400 uppercase\">Expiry (MM/YY)</label>\n                        <input\n                          type=\"text\"\n                          placeholder=\"MM/YY\"\n                          value={cardExpiry}\n                          onChange={handleExpiryChange}\n                          onFocus={() => setIsCardFlipped(false)}\n                          className=\"w-full bg-white px-3 py-1.5 border border-slate-250 text-xs rounded-xl focus:ring-1 focus:ring-emerald-500 outline-none font-mono text-center\"\n                          maxLength={5}\n                          required={paymentMethod === 'CREDIT_CARD' || paymentMethod === 'DEBIT_CARD'}\n                        />\n                      </div>\n\n                      <div className=\"space-y-1\">\n                        <label className=\"text-[9px] font-black text-slate-400 uppercase\">CVV (3 Digits)</label>\n                        <input\n                          type=\"password\"\n                          placeholder=\"•••\"\n                          value={cardCvv}\n                          onChange={(e) => setCardCvv(e.target.value.replace(/\\D/g, '').substring(0, 3))}\n                          onFocus={() => setIsCardFlipped(true)}\n                          onBlur={() => setIsCardFlipped(false)}\n                          className=\"w-full bg-white px-3 py-1.5 border border-slate-250 text-xs rounded-xl focus:ring-1 focus:ring-emerald-500 outline-none font-mono text-center\"\n                          maxLength={3}\n                          required={paymentMethod === 'CREDIT_CARD' || paymentMethod === 'DEBIT_CARD'}\n                        />\n                      </div>\n\n                      <div className=\"space-y-1\">\n                        <label className=\"text-[9px] font-black text-slate-400 uppercase\">ZIP Code</label>\n                        <input\n                          type=\"text\"\n                          placeholder=\"110017\"\n                          value={cardZip}\n                          onChange={(e) => setCardZip(e.target.value.replace(/\\D/g, '').substring(0, 6))}\n                          className=\"w-full bg-white px-3 py-1.5 border border-slate-250 text-xs rounded-xl focus:ring-1 focus:ring-emerald-500 outline-none font-mono text-center\"\n                          maxLength={6}\n                          required={paymentMethod === 'CREDIT_CARD' || paymentMethod === 'DEBIT_CARD'}\n                        />\n                      </div>\n                    </div>\n\n                  </div>\n                </div>\n              )}\n\n              {/* Razorpay element guide block */}\n              {paymentMethod === 'RAZORPAY' && (\n                <div className=\"p-4 bg-slate-50 rounded-2xl border border-slate-150 text-xs space-y-3 animate-fade-in text-slate-700\">\n                  <div className=\"flex justify-between items-center\">\n                    <span className=\"font-black text-slate-600 text-[10px] flex items-center gap-1 uppercase\">\n                      <ShieldCheck className=\"w-4 h-4 text-blue-600\" /> Razorpay Unified Secure Checkout\n                    </span>\n                    <span className=\"text-[8px] bg-white border px-1.5 font-bold uppercase rounded\">NPCI UPI Grounded</span>\n                  </div>\n\n                  <p className=\"text-[11px] leading-normal text-slate-500\">\n                    Choosing Razorpay allows you to pay securely via netbanking options or scanning standard QR codes.\n                  </p>\n                </div>\n              )}\n\n            </div>\n\n            {/* Step 3.5: Add Delivery Partner Tip */}\n            <div className=\"bg-white rounded-3xl p-5 border border-slate-100 shadow-xs space-y-3.5\">\n              <div className=\"flex items-center justify-between border-b border-slate-50 pb-2\">\n                <div className=\"flex items-center gap-2 text-slate-800 font-bold\">\n                  <span className=\"text-sm\">💝</span>\n                  <h3 className=\"text-xs font-black text-slate-700 uppercase tracking-wide\">3.5 Add Delivery Partner Tip</h3>\n                </div>\n                {deliveryTip > 0 && (\n                  <button \n                    type=\"button\" \n                    onClick={() => {\n                      setDeliveryTip(0);\n                      triggerNotification(\"Tip Removed 💝\", \"Delivery partner tip was reset to zero.\", \"info\");\n                    }}\n                    className=\"text-[9px] font-black uppercase text-rose-500 hover:text-rose-600 tracking-wider hover:underline cursor-pointer\"\n                  >\n                    Reset Tip\n                  </button>\n                )}\n              </div>\n\n              <p className=\"text-[10.5px] text-slate-400 font-medium leading-relaxed\">\n                100% of your generous tip goes directly to your e-bike delivery partner to appreciate their lightning-fast efforts.\n              </p>\n\n              <div className=\"grid grid-cols-4 gap-2\">\n                {[\n                  { value: 0, label: 'No Tip' },\n                  { value: 10, label: '₹10', desc: '☕ chai break' },\n                  { value: 20, label: '₹20', desc: '🍪 small treat' },\n                  { value: 50, label: '₹50', desc: '🚀 rider power' }\n                ].map((preset) => {\n                  const isSelected = deliveryTip === preset.value;\n                  return (\n                    <button\n                      key={preset.value}\n                      type=\"button\"\n                      onClick={() => {\n                        setDeliveryTip(preset.value);\n                        if (preset.value > 0) {\n                          triggerNotification(\"Tip Added! 💝\", `Thank you! Added a ₹${preset.value} tip for your delivery partner.`, \"success\");\n                        }\n                      }}\n                      className={`p-2 py-2.5 rounded-2xl text-center border transition active:scale-95 duration-150 cursor-pointer flex flex-col justify-center items-center ${\n                        isSelected \n                          ? 'border-emerald-600 bg-emerald-50 text-emerald-800 font-black ring-2 ring-emerald-500/10' \n                          : 'border-slate-100 bg-slate-50 hover:bg-slate-100 text-slate-500 hover:text-slate-700 font-bold'\n                      }`}\n                    >\n                      <span className=\"text-xs font-extrabold\">{preset.label}</span>\n                      {preset.desc && <span className=\"text-[7.5px] mt-0.5 font-normal opacity-75\">{preset.desc}</span>}\n                    </button>\n                  );\n                })}\n              </div>\n            </div>\n\n            {/* Step 4: Invoice Summary Box */}\n            <div className=\"bg-white rounded-3xl p-5 border border-slate-100 shadow-xs space-y-3 pb-4\">\n              <div className=\"flex items-center gap-2 text-slate-800 font-bold border-b border-slate-50 pb-2\">\n                <ShoppingBag className=\"w-4.5 h-4.5 text-emerald-600\" />\n                <h3 className=\"text-xs font-black text-slate-700 uppercase tracking-wide\">4. Review Bill Invoice Summaries</h3>\n              </div>\n\n               <div className=\"space-y-2 text-xs\">\n                <div className=\"flex justify-between text-slate-500\">\n                  <span>Basket Items Subtotal:</span>\n                  <span className=\"font-bold text-slate-800 font-mono\">₹{subtotal}</span>\n                </div>\n                <div className=\"flex justify-between text-slate-500\">\n                  <span>Standard delivery cargo:</span>\n                  <span className=\"font-bold text-slate-800 font-mono\">\n                    {deliveryFee === 0 || appliedCoupon === 'VIPDELIVERY' ? 'FREE' : `₹${deliveryFee}`}\n                  </span>\n                </div>\n                {deliveryTip > 0 && (\n                  <div className=\"flex justify-between text-emerald-700 font-bold bg-emerald-50 px-2 py-1.5 rounded-xl border border-emerald-100/50\">\n                    <span className=\"flex items-center gap-1\">Rider Delivery Tip 💝:</span>\n                    <span className=\"font-mono\">₹{deliveryTip}</span>\n                  </div>\n                )}\n                {finalDiscount > 0 && (\n                  <div className=\"flex justify-between text-emerald-600 font-extrabold bg-emerald-50 p-2 rounded-xl border border-emerald-100\">\n                    <span>Total Coupon & Rewards Discount:</span>\n                    <span className=\"font-mono\">-₹{finalDiscount}</span>\n                  </div>\n                )}\n                \n                <div className=\"h-px bg-slate-100 my-2\"></div>\n                \n                <div className=\"flex justify-between font-black text-sm text-slate-900 bg-slate-50 p-3 rounded-2xl border border-slate-150\">\n                  <span className=\"uppercase text-[11px] font-black text-slate-600 flex items-center gap-1\">\n                    Net Final Amount:\n                  </span>\n                  <span className=\"font-mono text-base text-emerald-700 flex items-center gap-1\">\n                    <span className=\"text-xs text-slate-400 line-through font-normal\">{finalDiscount > 0 ? `₹${subtotal + deliveryFee}` : ''}</span>\n                    ₹{netTotal}\n                  </span>\n                </div>\n              </div>\n\n              {/* Place submission button */}\n              <button\n                type=\"submit\"\n                disabled={isSubmittingOrder}\n                className=\"w-full mt-2 bg-emerald-600 hover:bg-emerald-700 disabled:bg-slate-400 text-white font-black py-3 px-6 rounded-2xl shadow-md transition transform active:scale-95 duration-100 cursor-pointer flex justify-between items-center text-xs\"\n              >\n                <span>\n                  {isSubmittingOrder ? 'TRANSACTING SECURE PAYMENTS...' : `CONFIRM & DEPOSIT ₹${netTotal} PAY`}\n                </span>\n                <span className=\"font-mono uppercase\">{paymentMethod === 'COD' ? 'PLACE COD ORDER' : `🔒 ${paymentMethod} SECUREPAY`}</span>\n              </button>\n            </div>\n          </form>\n\n        </div>\n      )}\n\n\n\n      {/* 4. STRIPE 3D-SECURE SECURE CODING POPUP VERIFIER (Meets requested features 